INSERT INTO `esend_articles` (`uuid`, `title`, `excerpt`, `content`, `image`, `category`, `publish_date`) VALUES
-- 1. RATS
('rats-monaco-copro', 'Invasion de rats à Monaco : Les risques pour les copropriétés', 'Les rats ne font pas de distinction sociale. À Monaco, les sous-sols et parkings de luxe sont des cibles privilégiées. Découvrez comment protéger votre patrimoine.', '<h2>Le défi monégasque de la dératisation</h2><p>Monaco, avec ses infrastructures souterraines denses, offre un habitat idéal pour les rongeurs. Les parkings et locaux techniques sont souvent les premiers points de colonisation.</p><h3>Pourquoi agir vite ?</h3><ul><li>Dommages électriques : Les câbles rongés sont la cause de pannes majeures.</li><li>Risques sanitaires : Transmission de maladies via les déjections.</li><li>Dégâts d''image : Une présence visible peut nuire au prestige de votre immeuble.</li></ul><p>ESEND propose des solutions de monitoring intelligent pour détecter toute intrusion avant qu''elle ne devienne une infestation.</p>', 'https://images.unsplash.com/photo-1594498653385-d5172c53ecd6?q=80&w=600', 'rats', '2026-04-02'),
('rats-deratisation-durable', 'Dératisation durable : Comment boucher les points d''entrée définitivement ?', 'Ne vous contentez pas de pièges. La vraie dératisation consiste à rendre votre logement impénétrable. Guide de l''expert ESEND.', '<h2>L''exclusion : La seule solution pérenne</h2><p>Le saviez-vous ? Un rat peut passer dans un trou de la taille d''une pièce de 2 euros. Boucher ces accès est la priorité numéro 1.</p><h3>Les matériaux recommandés</h3><ul><li>Laine d''acier épaisse</li><li>Mortier haute résistance</li><li>Grilles anti-rongeurs en inox</li></ul>', 'https://images.unsplash.com/photo-1594498653385-d5172c53ecd6?q=80&w=600', 'rats', '2026-04-02'),
('rats-methodes-naturelles', 'Pourquoi les méthodes ''naturelles'' échouent face aux surmulots', 'Le vinaigre blanc et les ultrasons ne suffiront pas. Comprendre l''intelligence du rat pour s''en débarrasser réellement.', '<h2>L''intelligence du surmulot</h2><p>Les rats sont néophobiques : ils se méfient de la nouveauté. Un diffuseur d''huiles essentielles sera ignoré en quelques heures.</p><h3>La science au service de l''hygiène</h3><p>Seuls des appâts professionnels à retardement permettent d''éliminer toute la colonie sans éveiller la méfiance des dominants.</p>', 'https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?q=80&w=600', 'rats', '2026-04-02'),

-- 2. PUNAISES
('punaises-menton-hotels', 'Punaises de lit à Menton : Pourquoi les hôtels sont-ils plus exposés ?', 'Le tourisme à Menton favorise le brassage de voyageurs. Pour les hôteliers, la prévention contre les punaises de lit est un enjeu de réputation vital.', '<h2>Tourisme et parasites : Un lien inséparable</h2><p>Menton attire des visiteurs du monde entier. Si cette dynamique est positive, elle augmente le risque d''introduction de punaises de lit via les bagages.</p><h3>Les bons réflexes de l''hôtelier</h3><p>La détection canine et les protocoles de nettoyage à haute température sont vos meilleurs alliés. Chez ESEND, nous formons votre personnel pour identifier les signes précoces.</p>', 'https://images.unsplash.com/photo-1595113316349-9fa4eb24f884?q=80&w=600', 'punaises-de-lit', '2026-04-02'),
('punaises-traitement-thermique', 'Traitement thermique vs Chimique : Le comparatif de l''expert ESEND', 'La punaise de lit résiste de plus en plus aux insecticides. Découvrez pourquoi la chaleur à 60°C est la solution la plus efficace.', '<h2>L''éradication par la chaleur</h2><p>Le traitement thermique consiste à monter la pièce en température. C''est l''unique méthode qui tue aussi les œufs.</p><h3>Avantages du thermique</h3><ul><li>Écologique : Zéro produit chimique</li><li>Instantané : Pas de rémanence</li><li>Pénétrant : Atteint l''intérieur des matelas</li></ul>', 'https://images.unsplash.com/photo-1584622650111-993a426fbf0a?q=80&w=600', 'punaises-de-lit', '2026-04-02'),
('punaises-detection-prevention', 'Comment détecter les punaises de lit avant qu''elles ne colonisent votre chambre ?', 'Ne vous laissez pas surprendre. Les premiers signes sont discrets mais sans équivoque si on sait où regarder.', '<h2>L''inspection préventive</h2><p>Vérifiez les coutures de matelas, les prises électriques et les cadres de lit. Cherchez des petits points noirs (déjections).</p><h3>Le rôle de l''expert</h3><p>ESEND utilise des détecteurs UV et des tests sanguins de surface pour valider la présence du parasite en 5 minutes.</p>', 'https://images.unsplash.com/photo-1595113316349-9fa4eb24f884?q=80&w=600', 'punaises-de-lit', '2026-04-02'),

-- 3. FRELONS
('frelons-asiatiques-06', 'Frelon Asiatique dans le 06 : Guide d''identification et danger', 'Le frelon asiatique colonise rapidement les Alpes-Maritimes. Reconnaître son nid et comprendre son agressivité est essentiel pour la sécurité de votre jardin.', '<h2>L''invasive Vespa Velutina à Menton</h2><p>Contrairement au frelon européen, le frelon asiatique construit souvent des nids massifs en haut des arbres ou sous les avant-toits.</p><h3>Que faire en cas de présence ?</h3><p>Ne tentez jamais de détruire un nid avec un jet d''eau. Les frelons attaqueront en masse. Contactez ESEND pour une destruction par injection de poudre biocide, une méthode sûre et radicale.</p>', 'https://images.unsplash.com/photo-1620912189865-1e8a33da4c5e?q=80&w=600', 'frelons', '2026-04-02'),
('frelons-nids-geants', 'Détruire un nid de guêpes : Pourquoi ne jamais le faire soi-même', 'Chaque année, des accidents graves surviennent à cause d''interventions imprudentes. Apprenez les risques réels.', '<h2>Le danger de l''attaque groupée</h2><p>Une guêpe en danger libère une phéromone d''alerte qui excite toute la colonie. Le risque de choc anaphylactique est réel après plusieurs piqûres.</p><h3>La sécurité d''abord</h3><p>ESEND intervient avec des combinaisons hermétiques de type 3 et des outils télescopiques jusqu''à 15 mètres de haut.</p>', 'https://images.unsplash.com/photo-1510253687831-0f982d7862fc?q=80&w=600', 'frelons', '2026-04-02'),
('frelons-saison-protection-jardin', 'Saison des frelons : Comment protéger votre jardin à Sospel et Menton', 'L''été approche. Installez des pièges sélectifs pour protéger vos abeilles et votre famille sans nuire à la biodiversité.', '<h2>Protection de l''écosystème local</h2><p>L''arrière-pays mentonnais est riche en biodiversité. Utiliser des pièges sélectifs permet de capturer uniquement les fondatrices de frelons asiatiques.</p><h3>Prévention printanière</h3><p>Le meilleur moment pour agir est le printemps, quand les reines cherchent à construire leur premier nid.</p>', 'https://images.unsplash.com/photo-1416870233980-7b7e6588339c?q=80&w=600', 'frelons', '2026-04-02'),

-- 4. CAFARDS
('cafards-cuisine-restaurant', 'Cafards en cuisine : Le protocole HACCP pour les restaurants', 'Un contrôle sanitaire peut fermer votre établissement. Découvrez comment ESEND garantit une cuisine sans blattes, conforme aux normes d''hygiène.', '<h2>L''exigence sanitaire Mentonnaise</h2><p>En restauration, la présence d''un seul cafard est une urgence absolue. Le protocole HACCP impose une lutte préventive rigoureuse.</p><h3>Notre approche pour les pros</h3><p>Nous utilisons des gels alimentaires de dernière génération, indétectables pour les clients mais foudroyants pour les colonies de blattes germaniques.</p>', 'https://images.unsplash.com/photo-1556910103-1c02745aae4d?q=80&w=600', 'cafards', '2026-04-02'),
('cafards-invasion-cloisons', 'Comment une seule blatte peut en cacher des milliers dans vos cloisons', 'La blatte est lucifuge : elle déteste la lumière. Si vous en voyez une en plein jour, c''est que l''infestation est déjà massive.', '<h2>Le pic de reproduction</h2><p>Une oothèque de blatte germanique peut contenir jusqu''à 40 œufs. En un an, une seule femelle peut engendrer des milliers de descendants.</p><h3>Intervention stratégique</h3><p>ESEND traite les zones de chaleur (moteurs de frigo, lave-vaisselle) pour tuer l''infestation à la source.</p>', 'https://images.unsplash.com/photo-1563227812-0ea4c22e6cc8?q=80&w=600', 'cafards', '2026-04-02'),
('cafards-gel-vs-pulverisation', 'Gel anti-cafards vs Pulvérisation : Quelle méthode pour votre appartement ?', 'Ne quittez plus votre logement pendant 4 heures. Découvrez la discrétion et l''efficacité chirurgicale du gel appât.', '<h2>L''évolution de la lutte insecticide</h2><p>La pulvérisation est souvent trop invasive. Le gel, lui, utilise l''effet de nécrophagie pour contaminer toute la colonie par contact.</p><h3>L''avantage ESEND</h3><p>Nos gels restent actifs pendant 3 mois, assurant une protection continue même après notre passage.</p>', 'https://images.unsplash.com/photo-1584622650111-993a426fbf0a?q=80&w=600', 'cafards', '2026-04-02'),

-- 5. DESINFECTION
('desinfection-diogene-deces', 'Désinfection après décès ou syndrome de Diogène : Un protocole strict', 'Intervenir dans des conditions extrêmes demande une expertise psychologique et technique. ESEND vous accompagne avec dignité.', '<h2>Une intervention délicate et technique</h2><p>Le syndrome de Diogène peut engendrer des risques infectieux majeurs. Nous procédons par évacuation totale et bio-nettoyage.</p><h3>Sécurisation de l''air</h3><p>Nous utilisons l''ozonothérapie pour neutraliser les odeurs et éliminer les bactéries en suspension dans l''air.</p>', 'https://images.unsplash.com/photo-1584483766114-2cea6facdf57?q=80&w=600', 'hygiene', '2026-04-02'),
('desinfection-bureaux-epidemie', 'Virucide et Bactéricide : Assainir ses bureaux après une épidémie', 'Le bien-être de vos employés passe par une hygiène irréprochable. Le protocole de désinfection tertiaire ESEND.', '<h2>Hygiène au travail : Un levier de performance</h2><p>Les claviers, poignées de porte et zones communes sont des vecteurs de virus. Une désinfection hebdomadaire réduit l''absentéisme.</p><h3>Nos produits éco-responsables</h3><p>ESEND utilise des solutions biodégradables, sans danger pour vos équipements informatiques ou de bureau.</p>', 'https://images.unsplash.com/photo-1497366216548-37526070297c?q=80&w=600', 'hygiene', '2026-04-02'),
('desinfection-nebulisation-technologie', 'Nébulisation : La technologie qui élimine 99.9% des pathogènes', 'Plus précis que le nettoyage manuel, le brouillard biocide atteint les moindres recoins de vos pièces.', '<h2>La désinfection par voie aérienne</h2><p>Le nébuliseur transforme le désinfectant en particules microscopiques. C''est la méthode reine pour les gymnases et crèches.</p><h3>Efficacité prouvée</h3><p>Certifié conforme à la norme NF EN 17272, notre protocole garantit une surface saine en moins de 15 minutes d''exposition.</p>', 'https://images.unsplash.com/photo-1584622650111-993a426fbf0a?q=80&w=600', 'hygiene', '2026-04-02'),

-- 6. NETTOYAGE
('nettoyage-fin-de-chantier-etapes', 'Nettoyage fin de chantier : Les 3 étapes pour une remise en état parfaite', 'Avant la remise des clés, assurez-vous que chaque poussière a disparu. Découvrez le check-up ESEND.', '<h2>Valoriser vos travaux à Menton</h2><p>Après les travaux, le voile de ciment et les poussières fines masquent la qualité de vos finitions. Un nettoyage professionnel est indispensable.</p><h3>Checklist ESEND</h3><ul><li>Dépoussiérage haute pression</li><li>Nettoyage des vitres et encadrements</li><li>Traitement des sols (cristallisation ou lustrage)</li></ul>', 'https://images.unsplash.com/photo-1503387762-592dea58ef03?q=80&w=600', 'maintenance', '2026-04-02'),
('nettoyage-toiture-menton-mousse', 'Nettoyage de toiture à Menton : Éviter les dégâts des eaux liés à la mousse', 'Le climat méditerranéen favorise le développement de lichens sur vos tuiles. Ne laissez pas votre toiture se dégrader.', '<h2>Entretien des toitures sur la Côte d''Azur</h2><p>L''humidité de mer et l''ensoleillement créent un cocktail propice aux micro-organismes. Des tuiles poreuses cassent plus facilement.</p><h3>Solution Algicide</h3><p>ESEND applique des traitements hydrofuges incolores qui laissent respirer le support tout en empêchant l''eau de s''y infiltrer.</p>', 'https://images.unsplash.com/photo-1632731804558-75e92160d5c0?q=80&w=600', 'maintenance', '2026-04-02'),
('nettoyage-sinistre-inondation', 'Remise en état après sinistre : Récupérer son logement après une inondation', 'Agir vite après une inondation évite l''apparition de moisissures irréversibles. Le protocole d''urgence ESEND.', '<h2>Gérer l''après-catastrophe</h2><p>L''eau stagnante est un danger pour les structures. Nous utilisons des déshumidificateurs industriels pour assécher les murs en profondeur.</p><h3>Décontamination post-sinistre</h3><p>Au-delà du séchage, nous traitons contre les germes importés par les eaux usées pour garantir un air sain dès votre retour.</p>', 'https://images.unsplash.com/photo-1544256718-3bcf237f3174?q=80&w=600', 'maintenance', '2026-04-02')
